import React, { useState, useCallback, useEffect, useMemo } from 'react';
import { useFocusEffect, useRouter } from 'expo-router';
import { View, ScrollView, TouchableOpacity, Animated, TextInput, Modal, FlatList } from 'react-native';
import { Text } from '@/components';
import LottieLoader from '@/components/LottieLoader';
import TrailMap from '@/components/TrailMap';
import TrailMapPopup from '@/components/TrailMapPopup';
import { useSafeAreaInsets } from 'react-native-safe-area-context';
import * as Location from 'expo-location';
import { getBestAvailableLocation } from '@/utils/location';
import * as Haptics from 'expo-haptics';
import { MapPin, Umbrella, Star, X, Navigation, ChevronLeft, Trees, TrafficCone, Mountain, List, Map } from 'lucide-react-native';
import theme from '@/constants/colors';
import { useTrails } from '@/context/TrailsContext';
import { Trail } from '@/types/trail';
import TrailCard from '@/components/TrailCard';
import styles from './explore.styles';

const CATEGORIES = [
  { id: 'for-you', name: 'For You', icon: Star },
  { id: 'nearby', name: 'Nearby', icon: MapPin },
  { id: 'beach', name: 'Beach', icon: Umbrella },
  { id: 'forest', name: 'Forest', icon: Trees },
  { id: 'road', name: 'Road', icon: TrafficCone },
  { id: 'cliff', name: 'Cliff', icon: Mountain },
];

export default function ExploreScreen() {
  const router = useRouter();
  const insets = useSafeAreaInsets();
  const { loadNearbyTrails, loadForYouTrails, loadTrailsByTag, saveTrailBookmark, removeTrailBookmark, isTrailSaved } = useTrails();
  const [selectedCategory, setSelectedCategory] = useState<string>('for-you');
  const [trails, setTrails] = useState<Trail[]>([]);
  const [isLoadingNearby, setIsLoadingNearby] = useState<boolean>(true);
  const [locationCoords, setLocationCoords] = useState<{ latitude: number; longitude: number } | undefined>(undefined);
  const [, setUserCity] = useState<string | undefined>(undefined);
  const [bookmarkAnimations, setBookmarkAnimations] = useState<Record<string, Animated.Value>>({});
  const [searchQuery, setSearchQuery] = useState<string>('');
  const [showSearchModal, setShowSearchModal] = useState<boolean>(false);
  const [currentLocation, setCurrentLocation] = useState<string>('');
  const [searchSuggestions, setSearchSuggestions] = useState<{ id: string; name: string; location: string; type: string }[]>([]);
  const [activeImageIndex, setActiveImageIndex] = useState<Record<string, number>>({});
  const [isCardSwiping, setIsCardSwiping] = useState<Record<string, boolean>>({});
  const [cardWidths, setCardWidths] = useState<Record<string, number>>({});
  const [viewMode, setViewMode] = useState<'list' | 'map'>('list');
  const [selectedMapTrailId, setSelectedMapTrailId] = useState<string | null>(null);
  const mainScrollRef = React.useRef<ScrollView>(null);

  const loadUserLocationAndNearbyTrails = useCallback(async () => {
    try {
      const { status } = await Location.requestForegroundPermissionsAsync();

      if (status === 'granted') {
        const location = await getBestAvailableLocation({ accuracy: Location.Accuracy.Balanced });

        // Skip reverse geocoding to avoid rate limits. We only need lat/lon for nearby search.
        setUserCity(undefined);
        if (location) {
          setCurrentLocation('Current location');
          setLocationCoords({ latitude: location.coords.latitude, longitude: location.coords.longitude });
        } else {
          setCurrentLocation('Location unavailable');
          setLocationCoords(undefined);
        }
      } else {
        setCurrentLocation('Location unavailable');
        setLocationCoords(undefined);
      }
    } catch (error) {
      console.error('Error loading location:', error);
      setCurrentLocation('Location unavailable');
      setLocationCoords(undefined);
    } finally {
      setIsLoadingNearby(false);
    }
  }, [loadNearbyTrails]);

  useEffect(() => {
    loadUserLocationAndNearbyTrails();
  }, [loadUserLocationAndNearbyTrails]);

  useFocusEffect(
    useCallback(() => {
      console.log('Explore tab focused - refreshing nearby trails');
      loadUserLocationAndNearbyTrails();
    }, [loadUserLocationAndNearbyTrails])
  );

  useEffect(() => {
    let cancelled = false;
    const loadForCategory = async () => {
      setIsLoadingNearby(true);
      try {
        if (selectedCategory === 'for-you') {
          const loaded = await loadForYouTrails(locationCoords?.latitude, locationCoords?.longitude);
          if (!cancelled) setTrails(loaded);
        } else if (selectedCategory === 'nearby') {
          const loaded = await loadNearbyTrails(locationCoords?.latitude, locationCoords?.longitude);
          if (!cancelled) setTrails(loaded);
        } else if (selectedCategory === 'beach' || selectedCategory === 'forest' || selectedCategory === 'road' || selectedCategory === 'cliff') {
          const tagMap: Record<string, string> = { beach: 'Beach', forest: 'Forest', road: 'Road', cliff: 'Cliff' };
          const tag = tagMap[selectedCategory] || selectedCategory;
          const loaded = await loadTrailsByTag(tag, locationCoords?.latitude, locationCoords?.longitude);
          if (!cancelled) setTrails(loaded);
        } else {
          if (!cancelled) setTrails([]);
        }
      } catch (err) {
        console.error('Failed to load category trails:', err);
        if (!cancelled) setTrails([]);
      } finally {
        if (!cancelled) setIsLoadingNearby(false);
      }
    };

    loadForCategory();
    return () => { cancelled = true; };
  }, [selectedCategory, locationCoords, loadNearbyTrails, loadForYouTrails, loadTrailsByTag]);

  const loadSearchSuggestions = useCallback(() => {
    const query = searchQuery.toLowerCase();

    const suggestions = trails
      .filter(trail => {
        const name = trail.name?.toLowerCase() || '';
        const city = trail.city?.toLowerCase() || '';
        const country = trail.country?.toLowerCase() || '';
        return name.includes(query) || city.includes(query) || country.includes(query);
      })
      .map(trail => ({
        id: trail.id,
        name: trail.name || `Trail ${new Date(trail.date).toLocaleDateString()}`,
        location: trail.city ? `${trail.city}, ${trail.country || 'Unknown'}` : 'Location unknown',
        type: 'trail',
      }))
      .slice(0, 6);

    setSearchSuggestions(suggestions);
  }, [searchQuery, trails]);

  useEffect(() => {
    if (searchQuery.trim()) {
      loadSearchSuggestions();
    } else {
      setSearchSuggestions([]);
    }
  }, [searchQuery, loadSearchSuggestions]);

  const handleSearchBarPress = () => {
    if (true) {
      Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
    }
    setShowSearchModal(true);
  };

  const handleCloseSearchModal = () => {
    if (true) {
      Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
    }
    setShowSearchModal(false);
    setSearchQuery('');
    setSearchSuggestions([]);
  };

  const handleSuggestionPress = (suggestionId: string) => {
    if (true) {
      Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
    }
    setShowSearchModal(false);
    setSearchQuery('');
    setSearchSuggestions([]);
    router.push(`/trail/${suggestionId}`);
  };

  const handleCurrentLocationPress = () => {
    if (true) {
      Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
    }
    setShowSearchModal(false);
    setSearchQuery('');
    setSearchSuggestions([]);
  };

  const getBookmarkAnimation = (trailId: string) => {
    if (!bookmarkAnimations[trailId]) {
      const newAnim = new Animated.Value(1);
      setBookmarkAnimations(prev => ({ ...prev, [trailId]: newAnim }));
      return newAnim;
    }
    return bookmarkAnimations[trailId];
  };

  const isValidUUID = (id: string): boolean => {
    const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
    return uuidRegex.test(id);
  };

  const handleBookmarkPress = async (trailId: string, isRealTrail: boolean = false) => {
    if (!isRealTrail && !isValidUUID(trailId)) {
      console.log('Cannot bookmark mock trail:', trailId);
      if (true) {
        Haptics.notificationAsync(Haptics.NotificationFeedbackType.Warning);
      }
      return;
    }

    if (true) {
      Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);
    }

    const anim = getBookmarkAnimation(trailId);
    const isSaved = isTrailSaved(trailId);

    Animated.sequence([
      Animated.timing(anim, {
        toValue: 0.6,
        duration: 100,
        useNativeDriver: true,
      }),
      Animated.spring(anim, {
        toValue: 1,
        friction: 3,
        tension: 100,
        useNativeDriver: true,
      }),
    ]).start();

    try {
      if (isSaved) {
        await removeTrailBookmark(trailId);
      } else {
        await saveTrailBookmark(trailId);
        if (true) {
          Haptics.notificationAsync(Haptics.NotificationFeedbackType.Success);
        }
      }
    } catch (error) {
      console.error('Failed to toggle bookmark:', error);
    }
  };

  const handleNavigateToTrail = (trailId: string) => {
    if (true) {
      Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
    }
    router.push(`/trail/${trailId}`);
  };

  const handleCategoryPress = (categoryId: string) => {
    if (true) {
      Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
    }
    setSelectedCategory(categoryId);
  };

  const mapMarkers = useMemo(() => {
    return trails
      .filter((trail) => Number.isFinite(trail.startLatitude) && Number.isFinite(trail.startLongitude))
      .map((trail) => ({
        id: trail.id,
        latitude: trail.startLatitude as number,
        longitude: trail.startLongitude as number,
        label: Number.isFinite(trail.dogMatchScore) ? `${trail.dogMatchScore.toFixed(1)}%` : '-',
      }));
  }, [trails]);

  const mapRegion = useMemo(() => {
    if (mapMarkers.length === 0) {
      return {
        latitude: locationCoords?.latitude ?? 40.7128,
        longitude: locationCoords?.longitude ?? -74.006,
        latitudeDelta: 0.2,
        longitudeDelta: 0.2,
      };
    }

    const latitudes = mapMarkers.map((marker) => marker.latitude);
    const longitudes = mapMarkers.map((marker) => marker.longitude);
    const minLat = Math.min(...latitudes);
    const maxLat = Math.max(...latitudes);
    const minLon = Math.min(...longitudes);
    const maxLon = Math.max(...longitudes);

    return {
      latitude: (minLat + maxLat) / 2,
      longitude: (minLon + maxLon) / 2,
      latitudeDelta: Math.max((maxLat - minLat) * 1.5, 0.03),
      longitudeDelta: Math.max((maxLon - minLon) * 1.5, 0.03),
    };
  }, [mapMarkers, locationCoords]);

  const handleViewToggle = () => {
    if (true) {
      Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
    }
    setViewMode((prev) => (prev === 'list' ? 'map' : 'list'));
    setSelectedMapTrailId(null);
  };

  const selectedMapTrail = useMemo(
    () => trails.find((t) => t.id === selectedMapTrailId) ?? null,
    [trails, selectedMapTrailId]
  );

  const selectedMapTrailCoordinates = useMemo(() => {
    if (!selectedMapTrail) return [];

    if (Array.isArray(selectedMapTrail.coordinates) && selectedMapTrail.coordinates.length > 1) {
      return selectedMapTrail.coordinates;
    }

    if (Array.isArray(selectedMapTrail.path) && selectedMapTrail.path.length > 1) {
      return selectedMapTrail.path
        .filter((point) => Array.isArray(point) && point.length >= 2)
        .map((point) => ({ latitude: point[1], longitude: point[0] }));
    }

    return [];
  }, [selectedMapTrail]);

  const renderCategoryHeader = () => (
    <View style={[styles.stickyHeader, { paddingTop: insets.top + 16 }]}>
      {/* <View style={styles.stickySearchContainer}>
        <TouchableOpacity
          style={styles.searchBar}
          onPress={handleSearchBarPress}
          activeOpacity={0.7}
        >
          <Search size={22} color={theme.textMuted} />
          <Text style={styles.searchPlaceholder}>Find Trails</Text>
          <View style={styles.filterButton}>
            <SlidersHorizontal size={18} color={theme.accentPrimary} />
          </View>
        </TouchableOpacity>
      </View> */}

      <View style={styles.categoriesSection}>
        <ScrollView
          horizontal
          showsHorizontalScrollIndicator={false}
          contentContainerStyle={styles.categoriesScroll}
        >
          {CATEGORIES.map((category) => {
            const Icon = category.icon;
            const isSelected = selectedCategory === category.id;

            return (
              <TouchableOpacity
                key={category.id}
                style={[
                  styles.categoryButton,
                  isSelected && styles.categoryButtonActive,
                ]}
                onPress={() => handleCategoryPress(category.id)}
              >
                <Icon
                  size={20}
                  color={isSelected ? theme.backgroundSecondary : theme.textMuted}
                  strokeWidth={2}
                />
                <Text
                  style={[
                    styles.categoryText,
                    isSelected && styles.categoryTextActive,
                  ]}
                >
                  {category.name}
                </Text>
              </TouchableOpacity>
            );
          })}
        </ScrollView>
      </View>
    </View>
  );

  return (
    <View style={styles.safeContainer}>
      {viewMode === 'list' ? (
        <ScrollView
          ref={mainScrollRef}
          scrollEnabled={!Object.values(isCardSwiping).some(Boolean)}
          style={styles.container}
          showsVerticalScrollIndicator={false}
          stickyHeaderIndices={[0]}
        >
          {renderCategoryHeader()}
          <View style={styles.categoryTrailsSection}>
            {isLoadingNearby ? (
              <View style={styles.loadingContainer}>
                <LottieLoader size={120} />
                <Text style={styles.loadingText}>Loading trails...</Text>
              </View>
            ) : trails.length > 0 ? (
              trails.map((trail) => {
                const isSaved = isTrailSaved(trail.id);
                return (
                  <TrailCard
                    key={trail.id}
                    trail={trail}
                    onPress={(id) => handleNavigateToTrail(id)}
                    onBookmarkPress={(id) => handleBookmarkPress(id, isValidUUID(id))}
                    isSaved={isSaved}
                    onSwipeStateChange={(id, swiping) => setIsCardSwiping(prev => ({ ...prev, [id]: swiping }))}
                  />
                );
              })
            ) : (
              <View style={styles.emptyContainer}>
                <MapPin size={48} color={theme.textMuted} />
                <Text style={styles.emptyText}>
                  No trails found yet. Record a trail to share with others!
                </Text>
              </View>
            )}
          </View>

          <View style={styles.bottomPadding} />
        </ScrollView>
      ) : (
        <View style={styles.container}>
          {renderCategoryHeader()}
          <View style={styles.mapViewContainer}>
            <View style={styles.mapCard}>
              <TrailMap
                style={{ flex: 1 }}
                initialRegion={mapRegion}
                coordinates={selectedMapTrailCoordinates}
                scrollEnabled
                zoomEnabled
                showStartMarker={false}
                showsUserLocation={!!locationCoords}
                userLocation={locationCoords ?? null}
                pointMarkers={mapMarkers}
                routeColor={theme.backgroundPrimary}
                routeWidth={5}
                routeOpacity={0.95}
                onPointMarkerPress={(id) => {
                  Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
                  setSelectedMapTrailId((prev) => (prev === id ? null : id));
                }}
              />
              {mapMarkers.length === 0 && (
                <View style={styles.mapEmptyOverlay}>
                  <Text style={styles.mapEmptyText}>No trail start points available for this category.</Text>
                </View>
              )}

              <TrailMapPopup
                trail={selectedMapTrail}
                onClose={() => setSelectedMapTrailId(null)}
                onViewTrail={(id) => {
                  setSelectedMapTrailId(null);
                  handleNavigateToTrail(id);
                }}
              />
            </View>
          </View>
        </View>
      )}

      <TouchableOpacity
        style={[styles.floatingToggleButton, { bottom: Math.max(insets.bottom + 12, 24) }]}
        onPress={handleViewToggle}
        activeOpacity={0.9}
      >
        {viewMode === 'list' ? (
          <Map size={20} color={theme.backgroundPrimary} strokeWidth={2.2} />
        ) : (
          <List size={20} color={theme.backgroundPrimary} strokeWidth={2.2} />
        )}
        <Text style={styles.floatingToggleText}>{viewMode === 'list' ? 'Map view' : 'List view'}</Text>
      </TouchableOpacity>

      <Modal
        visible={showSearchModal}
        animationType="slide"
        presentationStyle="fullScreen"
        onRequestClose={handleCloseSearchModal}
      >
        <View style={[styles.searchModalContainer, { paddingTop: insets.top }]}>
          <View style={styles.searchModalHeader}>
            <TouchableOpacity
              style={styles.backButton}
              onPress={handleCloseSearchModal}
            >
              <ChevronLeft size={24} color="#5d6b4a" />
            </TouchableOpacity>
            <View style={styles.searchModalInputContainer}>
              <TextInput
                style={styles.searchModalInput}
                placeholder="Find trails"
                placeholderTextColor="#9ca3af"
                value={searchQuery}
                onChangeText={setSearchQuery}
                autoFocus
                returnKeyType="search"
              />
              {searchQuery.length > 0 && (
                <TouchableOpacity
                  style={styles.clearButton}
                  onPress={() => setSearchQuery('')}
                >
                  <X size={20} color="#64748b" />
                </TouchableOpacity>
              )}
            </View>
          </View>

          <View style={styles.searchModalContent}>
            {searchQuery.trim() === '' && (
              <TouchableOpacity
                style={styles.currentLocationItem}
                onPress={handleCurrentLocationPress}
              >
                <View style={styles.locationIconContainer}>
                  <Navigation size={20} color="#5d6b4a" />
                </View>
                <View style={styles.locationTextContainer}>
                  <Text style={styles.locationTitle}>Current location</Text>
                  <Text style={styles.locationSubtitle}>{currentLocation}</Text>
                </View>
              </TouchableOpacity>
            )}

            {searchSuggestions.length > 0 && (
              <FlatList
                data={searchSuggestions}
                keyExtractor={(item) => item.id}
                renderItem={({ item }) => (
                  <TouchableOpacity
                    style={styles.suggestionItem}
                    onPress={() => handleSuggestionPress(item.id)}
                  >
                    <View style={styles.suggestionIconContainer}>
                      <MapPin size={20} color="#64748b" />
                    </View>
                    <View style={styles.suggestionTextContainer}>
                      <Text style={styles.suggestionTitle}>{item.name}</Text>
                      <Text style={styles.suggestionSubtitle}>{item.location}</Text>
                    </View>
                  </TouchableOpacity>
                )}
                showsVerticalScrollIndicator={false}
              />
            )}
          </View>
        </View>
      </Modal>
    </View>
  );
}
